What does this program print?

```cpp
#include <iostream>

enum class Status { ok, warn, error };

template <typename T>
struct Result
{
    Status s;
    T value;
};

int main()
{
    Result<int> r{ Status::warn, 42 };
    std::cout << static_cast<int>(r.s) << ' ' << r.value << '\n';
    return 0;
}
```

