What is wrong with this code?

```cpp
#include <iostream>

template <typename T>
struct Box { T value; };

void bump(Box<int> b) { b.value += 1; }

int main()
{
    Box<int> b{ 10 };
    bump(b);
    std::cout << b.value << '\n';
    return 0;
}
```

